{
  "name": "EduVision AI",
  "description": "An intelligent educational visualization system that helps teachers and students generate visual learning materials, flashcards, and gamified scenarios using AI."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type UserMode = 'TEACHER' | 'STUDENT';

export enum AppStep {
  MODE_SELECTION = 0,
  BASIC_INFO = 1,
  GOALS = 2,
  MODULE_SELECTION = 3,
  STUDENT_TRAITS = 4,
  RESULT = 5
}

export interface BasicInfo {
  age: string;
  subject: string;
  topic: string;
}

export interface Goals {
  learningGoal: string; // understanding, memory, application, creation, etc.
  timing: string; // intro, review, assessment, etc.
}

export interface StudentTraits {
  interests: string;
  differentiation: boolean;
}

export interface ModuleOption {
  id: string;
  title: string;
  description: string;
  icon: string;
}

export interface EduState {
  step: AppStep;
  mode: UserMode | null;
  basicInfo: BasicInfo;
  goals: Goals;
  selectedModules: string[];
  studentTraits: StudentTraits;
  aiSuggestion: string | null;
  finalResult: string | null;
  isGenerating: boolean;
  isSuggesting: boolean;
}

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_PROMPT } from '../constants';
import { EduState } from '../types';

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key is missing");
  return new GoogleGenAI({ apiKey });
};

export const suggestModules = async (state: EduState): Promise<string> => {
  const ai = getClient();

  const prompt = `
    Based on the following context, suggest the best combination of educational visualization modules (A, B, C, D, E).

    Context:
    - User Mode: ${state.mode}
    - Student Age/Grade: ${state.basicInfo.age}
    - Subject: ${state.basicInfo.subject}
    - Topic: ${state.basicInfo.topic}
    - Learning Goal: ${state.goals.learningGoal}
    - Timing: ${state.goals.timing}

    Please refer to the "Template Recommendations" in your system knowledge.

    Output Format:
    Return a concise suggestion starting with "建議組合：" followed by the modules and a 1-sentence reason. 
    Example: "建議組合：C 客製化圖卡 ＋ B 繪本場景。因為語文學習適合透過圖像記憶與情境故事結合。"
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.7,
      }
    });
    return response.text || "無法產生建議，請稍後再試。";
  } catch (error) {
    console.error("Gemini Suggestion Error:", error);
    return "AI 暫時忙碌中，請手動選擇。";
  }
};

export const generatePlan = async (state: EduState): Promise<string> => {
  const ai = getClient();

  // Constructing the user input flow as if the conversation happened
  const userRequest = `
    I have completed the requirements collection. Please generate the educational visualization design.

    1. Mode: ${state.mode === 'TEACHER' ? '👩‍🏫 教師模式' : '👨‍🎓 學生模式'}
    2. Target: ${state.basicInfo.age}, ${state.basicInfo.subject}, ${state.basicInfo.topic}
    3. Goal: ${state.goals.learningGoal}, Timing: ${state.goals.timing}
    4. Selected Modules: ${state.selectedModules.join(', ')}
    5. Student Traits: ${state.studentTraits.interests} (Differentiation: ${state.studentTraits.differentiation ? 'Yes' : 'No'})

    Please output the full design following the "Teaching Output Format" structure:
    1️⃣ Teaching Activity Design
    2️⃣ Visual/Image Design Description
    3️⃣ Image Generation Strategy (Provide Prompts)
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-preview',
      contents: userRequest,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.7,
        thinkingConfig: { thinkingBudget: 0 } // Disable thinking for faster response on standard tasks
      }
    });
    return response.text || "生成失敗，請重試。";
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    return `發生錯誤: ${(error as Error).message}`;
  }
};

import React from 'react';

interface LayoutProps {
  children: React.ReactNode;
  title?: string;
}

export const Layout: React.FC<LayoutProps> = ({ children, title }) => {
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center py-8 px-4 sm:px-6 lg:px-8">
      <div className="w-full max-w-4xl bg-white rounded-2xl shadow-xl overflow-hidden min-h-[80vh] flex flex-col">
        {/* Header */}
        <div className="bg-indigo-600 px-8 py-6 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <span className="text-3xl">🎓</span>
            <div>
              <h1 className="text-xl font-bold text-white tracking-wide">EduVision AI</h1>
              <p className="text-indigo-200 text-sm">Educational Visualization System</p>
            </div>
          </div>
          {title && <h2 className="text-white/90 font-medium text-sm bg-indigo-700/50 px-3 py-1 rounded-full">{title}</h2>}
        </div>

        {/* Content */}
        <div className="flex-1 p-8 overflow-y-auto relative">
          {children}
        </div>

        {/* Footer */}
        <div className="bg-slate-50 border-t border-slate-100 px-8 py-4 text-center text-slate-400 text-xs">
          Powered by Gemini 2.5 Flash • Built for Educators & Students
        </div>
      </div>
