      {/* Step 3: Modules */}
      {state.step === AppStep.MODULE_SELECTION && (
        <div className="space-y-6 animate-fade-in">
          <div className="flex justify-between items-center">
             <h2 className="text-2xl font-bold text-slate-800">步驟 3：選擇視覺模組</h2>
