import { GoogleGenAI } from "@google/genai";
import { SYSTEM_PROMPT } from '../constants';
import { EduState } from '../types';

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key is missing");
  return new GoogleGenAI({ apiKey });
};

export const suggestModules = async (state: EduState): Promise<string> => {
  const ai = getClient();

  const prompt = `
    Based on the following context, suggest the best combination of educational visualization modules (A, B, C, D, E).

    Context:
    - User Mode: ${state.mode}
    - Student Age/Grade: ${state.basicInfo.age}
    - Subject: ${state.basicInfo.subject}
    - Topic: ${state.basicInfo.topic}
    - Learning Goal: ${state.goals.learningGoal}
    - Timing: ${state.goals.timing}

    Please refer to the "Template Recommendations" in your system knowledge.

    Output Format:
    Return a concise suggestion IN TRADITIONAL CHINESE (繁體中文).
    Start with "建議組合：" followed by the modules and a 1-sentence reason. 
    Example: "建議組合：C 客製化圖卡 ＋ B 繪本場景。因為語文學習適合透過圖像記憶與情境故事結合。"
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.7,
      }
    });
    return response.text || "無法產生建議，請稍後再試。";
  } catch (error) {
    console.error("Gemini Suggestion Error:", error);
    return "AI 暫時忙碌中，請手動選擇。";
  }
};

export const generatePlan = async (state: EduState): Promise<string> => {
  const ai = getClient();

  const visualLanguageInstruction = state.visualLanguage === 'English' 
    ? "Visual Content Language: English (Any text, labels, or vocabulary on the images MUST be in English)." 
    : "Visual Content Language: Traditional Chinese (Any text, labels, or vocabulary on the images MUST be in Traditional Chinese).";

  // Constructing the user input flow as if the conversation happened
  const userRequest = `
    I have completed the requirements collection. Please generate the educational visualization design.

    1. Mode: ${state.mode === 'TEACHER' ? '👩‍🏫 教師模式' : '👨‍🎓 學生模式'}
    2. Target: ${state.basicInfo.age}, ${state.basicInfo.subject}, ${state.basicInfo.topic}
    3. Goal: ${state.goals.learningGoal}, Timing: ${state.goals.timing}
    4. Selected Modules: ${state.selectedModules.join(', ')}
    5. Student Traits: ${state.studentTraits.interests} (Differentiation: ${state.studentTraits.differentiation ? 'Yes' : 'No'})
    6. ${visualLanguageInstruction}

    Please output the full design following the "Teaching Output Format" structure.

    IMPORTANT: The entire response MUST be in TRADITIONAL CHINESE (繁體中文), EXCEPT for the image prompts which should follow the requested visual language logic.

    Sections:
    1️⃣ 教學活動設計 (Teaching Activity Design)
    2️⃣ 視覺／圖像設計說明 (Visual/Image Design Description)
    3️⃣ 圖像生成策略 (Image Generation Strategy - Provide Prompts in Code Blocks)

    CRITICAL INSTRUCTION FOR IMAGE PROMPTS (Section 3):
    - Ensure all prompts are wrapped in markdown code blocks like \`\`\` ... \`\`\`.
    - If "Visual Content Language" is English, explicitly include "Text in image: English" in the prompt.
    - If "Visual Content Language" is Chinese, explicitly include "Text in image: Traditional Chinese" in the prompt.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userRequest,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.7,
        thinkingConfig: { thinkingBudget: 0 } // Disable thinking for faster response on standard tasks
      }
    });
    return response.text || "生成失敗，請重試。";
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    return `發生錯誤: ${(error as Error).message}`;
  }
};

export const extractPrompts = (text: string): string[] => {
  // Matches content between ``` and ```
  // Handles potential language identifiers like ```text or ```markdown
  const codeBlockRegex = /```[\w]*\n([\s\S]*?)```/g;
  const matches = [];
  let match;

  while ((match = codeBlockRegex.exec(text)) !== null) {
    if (match[1]) {
      const content = match[1].trim();
      // Heuristic: Check if it looks like the prompt template provided in system prompt
      // e.g., contains "Output intent", "Subject:", "Style:"
      if (
        content.includes("Output intent") || 
        content.includes("Subject:") || 
        content.includes("Style:") ||
        content.includes("Target age:")
      ) {
        matches.push(content);
      }
    }
  }
  return matches;
};

export const generateImage = async (prompt: string): Promise<string> => {
  const ai = getClient();

  // Determine aspect ratio based on prompt content
  let aspectRatio = "4:3"; // Default landscape
  if (prompt.includes("1:1") || prompt.includes("square") || prompt.toLowerCase().includes("ratio: 1:1")) {
    aspectRatio = "1:1";
  } else if (prompt.includes("16:9") || prompt.toLowerCase().includes("ratio: 16:9")) {
    aspectRatio = "16:9";
  }

  try {
    // Using gemini-3-pro-image-preview for high quality images
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [
          { text: prompt },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio as any,
          imageSize: "1K"
        }
      },
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image data found in response");
  } catch (error) {
    console.error("Image Generation Error:", error);
    throw error;
  }
};

