export interface ExtractedPrompt {
  prompt: string;
  aspectRatio: '1:1' | '4:3' | '16:9';
}

export const extractPrompts = (text: string): ExtractedPrompt[] => {
  // Regex to find the JSON block at the end or anywhere in the text
  const jsonBlockRegex = /```json\n([\s\S]*?)```/g;
  const matches = [];
  let match;

  while ((match = jsonBlockRegex.exec(text)) !== null) {
    if (match[1]) {
      try {
        const json = JSON.parse(match[1]);
        if (Array.isArray(json)) {
          matches.push(...json);
        }
      } catch (e) {
        console.warn("Failed to parse JSON prompt block", e);
      }
    }
  }

  // Map to internal format
  return matches.map((m: any) => ({
    prompt: m.prompt || "",
    aspectRatio: m.aspect_ratio || "4:3"
  })).filter(p => p.prompt.length > 0);
};

export const generateImage = async (prompt: string, aspectRatioInput: string = "4:3"): Promise<string> => {
  const ai = getClient();

  // Normalize aspect ratio
  let aspectRatio: "1:1" | "3:4" | "4:3" | "16:9" | "9:16" = "4:3";
  if (aspectRatioInput === "1:1") aspectRatio = "1:1";
  if (aspectRatioInput === "16:9") aspectRatio = "16:9";

  try {
    // Using gemini-3-pro-image-preview for high quality images
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [
          { text: prompt },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio,
          imageSize: "1K"
        }
      },
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image data found in response");
  } catch (error) {
    console.error("Image Generation Error:", error);
    throw error;
  }
};

