          <div key={img.id} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden flex flex-col transition-all hover:shadow-md">
            {/* Image View Area */}
            <div className={`aspect-[4/3] bg-slate-50 relative group flex items-center justify-center border-b border-slate-100`}>
              {img.status === 'completed' && img.url ? (
                <>
                  <img src={img.url} alt={`Generated ${index + 1}`} className="w-full h-full object-contain" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-3">
                    <button onClick={() => setSelectedImage(img)} className="p-3 bg-white rounded-full hover:bg-slate-100 shadow-lg transition-transform hover:scale-110">
                      <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0zM10 7v3m0 0v3m0-3h3m-3 0H7" /></svg>
                    </button>
                    <button onClick={() => handleDownload(img)} className="p-3 bg-white rounded-full hover:bg-slate-100 shadow-lg transition-transform hover:scale-110">
                      <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                    </button>
                  </div>
                </>
              ) : img.status === 'error' ? (
                <div className="text-center p-6 bg-red-50/50 w-full h-full flex flex-col items-center justify-center">
                  <span className="text-4xl mb-2">⚠️</span>
                  <p className="text-red-600 font-bold">生成失敗</p>
                  <p className="text-xs text-red-400 mt-1">{img.error}</p>
                </div>
              ) : img.status === 'generating' ? (
                <div className="flex flex-col items-center animate-pulse">
                   <div className="animate-spin rounded-full h-12 w-12 border-4 border-indigo-600 border-t-transparent mb-4"></div>
                   <p className="text-sm font-medium text-indigo-600">AI 正在繪製中...</p>
                </div>
              ) : (
                <div className="flex flex-col items-center p-8 text-center text-slate-400">
                  <svg className="w-16 h-16 mb-4 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                  <p className="text-sm">尚未生成圖像，請確認下方提示詞後點擊生成。</p>
                </div>
              )}
            </div>

            {/* Prompt Editor Area */}
            <div className="p-6 flex-1 flex flex-col">
              <div className="flex items-center justify-between mb-2">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">生圖提示詞 (Prompt)</span>
                <button 
                  onClick={() => setEditingId(editingId === img.id ? null : img.id)}
                  className="text-xs text-indigo-600 hover:text-indigo-800 font-bold"
                >
                  {editingId === img.id ? '完成編輯' : '編輯內容'}
                </button>
              </div>

              <div className="flex-1 relative mb-4">
                {editingId === img.id ? (
                  <textarea
                    autoFocus
                    className="w-full h-32 p-3 text-sm font-mono bg-slate-50 border border-indigo-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none resize-none"
                    value={img.editedPrompt || img.prompt}
                    onChange={(e) => onUpdatePrompt(img.id, e.target.value)}
                  />
                ) : (
                  <div className="w-full h-32 p-3 text-sm font-mono bg-slate-50 border border-slate-100 rounded-xl text-slate-600 overflow-y-auto italic">
                    {img.editedPrompt || img.prompt}
