                <div className="flex items-center gap-2">
                  <span className="px-2 py-1 bg-slate-100 text-slate-500 rounded text-[10px] font-bold">ASPECT {img.aspectRatio}</span>
                </div>
                <button 
                  onClick={() => onGenerateSingle(img.id)}
                  disabled={img.status === 'generating'}
                  className={`px-6 py-2 rounded-xl font-bold text-sm transition-all shadow-sm ${img.status === 'completed' ? 'bg-slate-100 text-slate-600 hover:bg-slate-200' : 'bg-indigo-600 text-white hover:bg-indigo-700 hover:shadow-md'}`}
                >
                  {img.status === 'generating' ? '生成中...' : (img.status === 'completed' ? '重新生成' : '立即生成')}
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Zoom Modal */}
      {selectedImage && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-md" onClick={() => setSelectedImage(null)}>
