            <img src={selectedImage.url!} alt="Zoomed" className="max-w-full max-h-[80vh] object-contain rounded-lg shadow-2xl" />
            <div className="mt-6 flex gap-4">
              <button onClick={() => handleDownload(selectedImage)} className="px-8 py-3 bg-white text-indigo-600 font-bold rounded-xl hover:bg-slate-100 transition shadow-xl flex items-center gap-2">
